using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ConfigMcpServer.Tools;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Get the value of a configuration setting by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'AppName', 'MaxRetries')")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? value
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("List all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfiguration.Current.Keys.Order());
    }

    [McpServerTool, Description("Update a configuration setting. Returns the previous value.")]
    public static string SetConfigValue(
        [Description("The configuration key to update")] string key,
        [Description("The new value to set")] string value)
    {
        var config = AppConfiguration.Current;
        var previous = config.TryGetValue(key, out var old) ? old : "(not set)";
        config[key] = value;
        return $"Updated '{key}': {previous} → {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ConfigMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(UriTemplate = "config://app/all", Name = "Full App Configuration",
        MimeType = "application/json"),
     Description("Returns the complete application configuration as JSON.")]
    public static string GetAllConfig()
    {
        return JsonSerializer.Serialize(AppConfiguration.Current, JsonOptions);
    }

    [McpServerResource(UriTemplate = "config://app/environment", Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironmentInfo()
    {
        var info = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessId = Environment.ProcessId,
            StartTime = DateTime.UtcNow.ToString("o")
        };
        return JsonSerializer.Serialize(info, JsonOptions);
    }
}

namespace ConfigMcpServer;

/// <summary>
/// Simple in-memory configuration store shared across tools and resources.
/// Replace with a real config provider (database, Azure App Configuration, etc.) in production.
/// </summary>
public static class AppConfiguration
{
    public static Dictionary<string, string> Current { get; } = new()
    {
        ["AppName"] = "ConfigMcpServer",
        ["Version"] = "1.0.0",
        ["MaxRetries"] = "3",
        ["TimeoutSeconds"] = "30",
        ["LogLevel"] = "Information",
        ["FeatureFlag:DarkMode"] = "true",
        ["FeatureFlag:BetaApi"] = "false"
    };
}

